mapper.select:
SELECT cnum, cwriter, CCONTENT, cdate row_num FROM (SELECT cnum, cwriter, CCONTENT, cdate ROW_NUMBER() OVER(ORDER BY num desc) AS row_num FROM comments
writer like '%' || #{searchValue} || '%'
title like '%' || #{searchValue} || '%'
content like '%' || #{searchValue} || '%'
) numbered_rows WHERE row_num BETWEEN #{begin} AND #{end}
